package com.maum.domain.user.entity

import jakarta.persistence.*

@Entity
@Table(name = "users")
class User(
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    val id: Long = 0L,

    @Column(nullable = false, unique = true, length = 50)
    val nickname: String,

    @Column(nullable = false, unique = true, length = 100)
    val email: String,

    @Column(nullable = false)
    val isActive: Boolean = true,
) {
    override fun equals(other: Any?): Boolean {
        if (this === other) return true
        if (other !is User) return false
        return id == other.id
    }

    override fun hashCode(): Int = id.hashCode()

    override fun toString(): String = "User(id=$id, nickname=$nickname, email=$email)"
}

package com.maum.domain.follow.entity

import com.maum.domain.user.entity.User
import jakarta.persistence.*
import java.time.LocalDateTime

@Entity
@Table(
    name = "follows",
    uniqueConstraints = [UniqueConstraint(columnNames = ["follower_id", "following_id"])]
)
class Follow(
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    val id: Long = 0L,

    // 팔로우를 거는 사람
    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "follower_id", nullable = false)
    val follower: User,

    // 팔로우를 받는 사람
    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "following_id", nullable = false)
    val following: User,

    @Column(nullable = false)
    val createdAt: LocalDateTime = LocalDateTime.now(),
) {
    override fun equals(other: Any?): Boolean {
        if (this === other) return true
        if (other !is Follow) return false
        return id == other.id
    }

    override fun hashCode(): Int = id.hashCode()

    override fun toString(): String =
        "Follow(id=$id, followerId=${follower.id}, followingId=${following.id})"
}

package com.maum.domain.follow.repository

import com.maum.domain.follow.entity.Follow
import com.maum.domain.user.entity.User
import org.springframework.data.jpa.repository.JpaRepository
import org.springframework.data.jpa.repository.Query
import org.springframework.data.repository.query.Param
import org.springframework.stereotype.Repository

@Repository
interface FollowRepository : JpaRepository<Follow, Long> {

    // follower -> following 관계 존재 여부
    fun existsByFollowerAndFollowing(follower: User, following: User): Boolean

    // follower -> following 관계 조회
    fun findByFollowerAndFollowing(follower: User, following: User): Follow?

    // userId를 팔로우하는 사람 목록 (팔로워)
    @Query("SELECT f.follower FROM Follow f WHERE f.following.id = :userId")
    fun findFollowersByUserId(@Param("userId") userId: Long): List<User>

    // userId가 팔로우하는 사람 목록 (팔로잉)
    @Query("SELECT f.following FROM Follow f WHERE f.follower.id = :userId")
    fun findFollowingsByUserId(@Param("userId") userId: Long): List<User>

    fun deleteByFollowerAndFollowing(follower: User, following: User)
}

