        // then
        verify(followRepository).save(any<Follow>())
    }

    @Test
    fun `should throw IllegalStateException when already following`() {
        // given
        val follower = createUser(id = 1L)
        val following = createUser(id = 2L)

        whenever(userRepository.findById(1L)).thenReturn(Optional.of(follower))
        whenever(userRepository.findById(2L)).thenReturn(Optional.of(following))
        whenever(followRepository.existsByFollowerAndFollowing(follower, following)).thenReturn(true)

        // when & then
        val exception = assertThrows<IllegalStateException> {
            userService.follow(followerId = 1L, followingId = 2L)
