        whenever(userRepository.findById(nonExistentFollowingId)).thenReturn(Optional.empty())

        // when & then
        val exception = assertThrows<NoSuchElementException> {
            userService.follow(followerId = 1L, followingId = nonExistentFollowingId)
        }

        assertThat(exception.message).contains("팔로잉 대상 유저를 찾을 수 없습니다")
        verify(followRepository, never()).save(any<Follow>())
    }

