        val following = createUser(id = 2L, nickname = "followingUser")

        whenever(userRepository.findById(1L)).thenReturn(Optional.of(follower))
        whenever(userRepository.findById(2L)).thenReturn(Optional.of(following))
        whenever(followRepository.existsByFollowerAndFollowing(follower, following)).thenReturn(false)

        // when
        userService.follow(followerId = 1L, followingId = 2L)

        // then
        verify(followRepository).save(any<Follow>())
    }

    @Test
    fun `should throw IllegalStateException when already following`() {
        // given
        val follower = createUser(id = 1L)
        val following = createUser(id = 2L)

        whenever(userRepository.findById(1L)).thenReturn(Optional.of(follower))
        whenever(userRepository.findById(2L)).thenReturn(Optional.of(following))
        whenever(followRepository.existsByFollowerAndFollowing(follower, following)).thenReturn(true)

        // when & then
        val exception = assertThrows<IllegalStateException> {
            userService.follow(followerId = 1L, followingId = 2L)
        }

        assertThat(exception.message).contains("이미 팔로우 중인 유저")
        verify(followRepository, never()).save(any<Follow>())
    }

    @Test
    fun `should throw IllegalArgumentException when follower and following are same user`() {
        // given
        val sameUserId = 1L

        // when & then
        val exception = assertThrows<IllegalArgumentException> {
            userService.follow(followerId = sameUserId, followingId = sameUserId)
        }

        assertThat(exception.message).contains("자기 자신을 팔로우할 수 없습니다")
        verify(userRepository, never()).findById(any())
        verify(followRepository, never()).save(any<Follow>())
    }

    @Test
    fun `should throw NoSuchElementException when following user does not exist`() {
        // given
        val follower = createUser(id = 1L)
        val nonExistentFollowingId = 999L

        whenever(userRepository.findById(1L)).thenReturn(Optional.of(follower))
        whenever(userRepository.findById(nonExistentFollowingId)).thenReturn(Optional.empty())

        // when & then
        val exception = assertThrows<NoSuchElementException> {
            userService.follow(followerId = 1L, followingId = nonExistentFollowingId)
        }

        assertThat(exception.message).contains("팔로잉 대상 유저를 찾을 수 없습니다")
        verify(followRepository, never()).save(any<Follow>())
    }

    @Test
    fun `should throw NoSuchElementException when follower user does not exist`() {
        // given
        val nonExistentFollowerId = 999L

        whenever(userRepository.findById(nonExistentFollowerId)).thenReturn(Optional.empty())

        // when & then
        val exception = assertThrows<NoSuchElementException> {
            userService.follow(followerId = nonExistentFollowerId, followingId = 2L)
        }

        assertThat(exception.message).contains("팔로워 유저를 찾을 수 없습니다")
        verify(followRepository, never()).save(any<Follow>())
    }

    // ===== unfollow() 테스트 =====

    @Test
    fun `should unfollow successfully when follow relationship exists`() {
        // given
        val follower = createUser(id = 1L)
        val following = createUser(id = 2L)

        whenever(userRepository.findById(1L)).thenReturn(Optional.of(follower))
        whenever(userRepository.findById(2L)).thenReturn(Optional.of(following))
        whenever(followRepository.existsByFollowerAndFollowing(follower, following)).thenReturn(true)

        // when
        userService.unfollow(followerId = 1L, followingId = 2L)

        // then
        verify(followRepository).deleteByFollowerAndFollowing(follower, following)
    }

    @Test
    fun `should throw IllegalStateException when trying to unfollow user not followed`() {
        // given
        val follower = createUser(id = 1L)
        val following = createUser(id = 2L)

        whenever(userRepository.findById(1L)).thenReturn(Optional.of(follower))
        whenever(userRepository.findById(2L)).thenReturn(Optional.of(following))
        whenever(followRepository.existsByFollowerAndFollowing(follower, following)).thenReturn(false)

        // when & then
        val exception = assertThrows<IllegalStateException> {
            userService.unfollow(followerId = 1L, followingId = 2L)
        }

        assertThat(exception.message).contains("팔로우 관계가 존재하지 않습니다")
        verify(followRepository, never()).deleteByFollowerAndFollowing(any(), any())
    }

    // ===== getFollowers() 테스트 =====

    @Test
    fun `should return followers list when user has followers`() {
        // given
        val userId = 1L
        val follower1 = createUser(id = 2L, nickname = "follower1")
        val follower2 = createUser(id = 3L, nickname = "follower2")
        val expectedFollowers = listOf(follower1, follower2)

        whenever(followRepository.findFollowersByUserId(userId)).thenReturn(expectedFollowers)

        // when
        val result = userService.getFollowers(userId)

        // then
        assertThat(result).hasSize(2)
        assertThat(result).containsExactlyInAnyOrder(follower1, follower2)
        verify(followRepository).findFollowersByUserId(userId)
    }

    @Test
    fun `should return empty list when user has no followers`() {
        // given
        val userId = 1L

        whenever(followRepository.findFollowersByUserId(userId)).thenReturn(emptyList())

        // when
        val result = userService.getFollowers(userId)

        // then
        assertThat(result).isEmpty()
        verify(followRepository).findFollowersByUserId(userId)
    }

    // ===== getFollowings() 테스트 =====

    @Test
    fun `should return followings list when user follows others`() {
        // given
        val userId = 1L
        val following1 = createUser(id = 2L, nickname = "following1")
        val following2 = createUser(id = 3L, nickname = "following2")
        val expectedFollowings = listOf(following1, following2)

        whenever(followRepository.findFollowingsByUserId(userId)).thenReturn(expectedFollowings)

        // when
        val result = userService.getFollowings(userId)

        // then
        assertThat(result).hasSize(2)
        assertThat(result).containsExactlyInAnyOrder(following1, following2)
