        // given
        val userId = 1L

        whenever(followRepository.findFollowingsByUserId(userId)).thenReturn(emptyList())

        // when
        val result = userService.getFollowings(userId)

        // then
        assertThat(result).isEmpty()
        verify(followRepository).findFollowingsByUserId(userId)
    }
