```kotlin
package com.maum.user.service

import com.maum.domain.follow.entity.Follow
import com.maum.domain.follow.repository.FollowRepository
import com.maum.domain.user.entity.User
import com.maum.domain.user.repository.UserRepository
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional

@Service
@Transactional(readOnly = true)
class UserService(
    private val userRepository: UserRepository,
    private val followRepository: FollowRepository,
) {

    @Transactional
    fun follow(followerId: Long, followingId: Long) {
        if (followerId == followingId) {
            throw IllegalArgumentException("자기 자신을 팔로우할 수 없습니다.")
        }
        val follower = userRepository.findById(followerId)
            .orElseThrow { NoSuchElementException("팔로워 유저를 찾을 수 없습니다. id=$followerId") }
        val following = userRepository.findById(followingId)
            .orElseThrow { NoSuchElementException("팔로잉 대상 유저를 찾을 수 없습니다. id=$followingId") }

        if (followRepository.existsByFollowerAndFollowing(follower, following)) {
            throw IllegalStateException("이미 팔로우 중인 유저입니다.")
        }
        followRepository.save(Follow(follower = follower, following = following))
    }

    @Transactional
    fun unfollow(followerId: Long, followingId: Long) {
        val follower = userRepository.findById(followerId)
            .orElseThrow { NoSuchElementException("팔로워 유저를 찾을 수 없습니다. id=$followerId") }
        val following = userRepository.findById(followingId)
            .orElseThrow { NoSuchElementException("팔로잉 대상 유저를 찾을 수 없습니다. id=$followingId") }

        if (!followRepository.existsByFollowerAndFollowing(follower, following)) {
            throw IllegalStateException("팔로우 관계가 존재하지 않습니다.")
        }
        followRepository.deleteByFollowerAndFollowing(follower, following)
    }

    fun getFollowers(userId: Long): List<User> = followRepository.findFollowersByUserId(userId)

    fun getFollowings(userId: Long): List<User> = followRepository.findFollowingsByUserId(userId)
}
```

